mapper.select:
select id, tenant_id, file_id, pipeline_instance_id, channel_code, dispatch_target, dispatch_status, dispatch_attempt, receipt_code, receipt_status, external_request_id, error_code, error_message, error_key, error_args, dispatched_at, ack_at, created_at, updated_at from batch.file_dispatch_record where tenant_id = #{q.tenantId}
and file_id = #{q.fileId}
and channel_code = #{q.channelCode}
and dispatch_status = #{q.dispatchStatus}
and receipt_status = #{q.receiptStatus}
and created_at >= #{q.fromTime}
and created_at <= #{q.toTime}
order by id desc
limit #{q.pageRequest.pageSize} offset (#{q.pageRequest.pageNo} - 1) * #{q.pageRequest.pageSize}

select count(1)
from batch.file_dispatch_record
where tenant_id = #{q.tenantId}

    and file_id = #{q.fileId}


    and channel_code = #{q.channelCode}


    and dispatch_status = #{q.dispatchStatus}


    and receipt_status = #{q.receiptStatus}


    and created_at >= #{q.fromTime}


    and created_at <= #{q.toTime}
